async function main() {
  const input = $input.item.json.output;

  // Extrai a data de ciência (formato dd/mm/yyyy)
  const parts = input.data_ciencia.split("/");
  const dataCiencia = new Date(parts[2], parts[1] - 1, parts[0]);
  const ano = dataCiencia.getFullYear();

  // Busca os feriados nacionais via BrasilAPI
  let feriadosNacionais = [];
  try {
    const feriados = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://brasilapi.com.br/api/feriados/v1/${ano}`,
      json: true
    });
    feriadosNacionais = feriados.map(f => f.date); // formato YYYY-MM-DD
  } catch (error) {
    // Fallback mínimo se a API estiver fora do ar
    feriadosNacionais = [
      `${ano}-01-01`, `${ano}-04-21`, `${ano}-05-01`,
      `${ano}-09-07`, `${ano}-10-12`, `${ano}-11-02`,
      `${ano}-11-15`, `${ano}-12-25`
    ];
  }

  // Funções auxiliares
  function isWeekend(date) {
    const day = date.getDay();
    return day === 0 || day === 6;
  }

  function isFeriado(date) {
    const dateStr = date.toISOString().split("T")[0];
    return feriadosNacionais.includes(dateStr);
  }

  function proximoDiaUtil(date) {
    let novaData = new Date(date);
    while (isWeekend(novaData) || isFeriado(novaData)) {
      novaData.setDate(novaData.getDate() + 1);
    }
    return novaData;
  }

  function formatDate(date) {
    const d = String(date.getDate()).padStart(2, "0");
    const m = String(date.getMonth() + 1).padStart(2, "0");
    const y = date.getFullYear();
    return `${d}/${m}/${y}`;
  }
    // --- NOVA FUNÇÃO PARA FORMATAR "1 de dezembro de 2025" ---
function formatarDataPorExtenso(date) {
  const meses = [
    "janeiro", "fevereiro", "março", "abril", "maio", "junho",
    "julho", "agosto", "setembro", "outubro", "novembro", "dezembro"
  ];
  return `${date.getDate()} de ${meses[date.getMonth()]} de ${date.getFullYear()}`;
}

// Data de submissão = data atual
const dataSubmissao = new Date();

  // Calcula a data de início (dia seguinte à ciência)
  let dataInicio = new Date(dataCiencia);
  dataInicio.setDate(dataInicio.getDate() + 1);

  // Se o dia seguinte for sábado/domingo → pula pro próximo dia útil (segunda ou posterior)
  dataInicio = proximoDiaUtil(dataInicio);

  // Calcula a data final (30 dias corridos após o início)
  let dataFim = new Date(dataInicio);
  dataFim.setDate(dataFim.getDate() + 29);
  dataFim = proximoDiaUtil(dataFim); // ajusta se cair em fds/feriado

  return {
    input,
    data_inicio_prazo: formatDate(dataInicio),
    data_fim_prazo: formatDate(dataFim),
    data_submissao: formatarDataPorExtenso(dataSubmissao)
  };
}

return main();

