const pages = $json.text;

let paginaDespacho = null;
let paginaDetalhamento = null;

pages.forEach((pageText, index) => {
  const text = pageText.toUpperCase();

  // === DESPACHO DECISÓRIO (CORPO REAL) ===
  const hasTituloDespacho = text.includes("DESPACHO DECISÓRIO");
  const hasEstruturaNumerada =
    text.includes("1-SUJEITO PASSIVO") ||
    text.includes("1 – SUJEITO PASSIVO") ||
    text.includes("2-IDENTIFICAÇÃO") ||
    text.includes("3-FUNDAMENTAÇÃO");

  // Evita página de ciência / aviso
  const isAvisoCiencia =
    text.includes("CIENTIFICADO DO DESPACHO DECISÓRIO") &&
    !hasTituloDespacho;

  if (
    paginaDespacho === null &&
    hasTituloDespacho &&
    hasEstruturaNumerada &&
    !isAvisoCiencia
  ) {
    paginaDespacho = index + 1;
  }

  // === DETALHAMENTO DA COMPENSAÇÃO ===
  const hasDetalhamento =
    text.includes("DETALHAMENTO DA COMPENSAÇÃO") &&
    text.includes("VALORES DEVEDORES");

  if (
    paginaDetalhamento === null &&
    hasDetalhamento
  ) {
    paginaDetalhamento = index + 1;
  }
});

// Fallback padrão (se não encontrou nada)
paginaDespacho = paginaDespacho ?? 2;
paginaDetalhamento = paginaDetalhamento ?? 3;

return {
  pagina_despacho_decisorio: paginaDespacho,
  pagina_detalhamento_compensacao: paginaDetalhamento,
  ...$json
};

